sql:
SELECT CEIL(
  (COUNT(CASE WHEN socio_economic_status != 'Low' THEN 1 END) * 100.0) / COUNT(student_id)
) AS non_low_socio_economic_status_percentage
FROM students;

SELECT s.student_id, s.age 
FROM students s
WHERE s.student_id IN (SELECT student_id FROM educational_pathways);

